import{_ as e,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"mParticle (Export) Configuration","description":"","frontmatter":{"title":"mParticle (Export) Configuration","slug":"mparticle-export-configuration"},"headers":[],"relativePath":"developer-hub/mparticle-export-configuration.md","filePath":"developer-hub/mparticle-export-configuration.md"}'),i={name:"developer-hub/mparticle-export-configuration.md"};function n(d,t,l,s,c,h){return a(),r("div",null,[...t[0]||(t[0]=[o('<p><em>[Image: 1328]</em></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>With a push of a button you can send your Branch data to your mParticle dashboard, helping you to understand the power of Branch as an acquisition pathway, export your data to your entire suite of analytics tools and build custom audiences upon Branch data.</p><p>This documentation explains how to send <strong>Branch events to mParticle</strong>. mParticle calls this an Inbound Feed Integration.</p><p>If you&#39;d like to send mParticle events to Branch through your app, please review the Branch/mParticle SDK Kit integration documentation for <a href="https://help.branch.io/" target="_blank" rel="noreferrer">iOS</a> and <a href="https://help.branch.io/" target="_blank" rel="noreferrer">Android</a>.</p><p>If you&#39;d like to send mParticle events to Branch through a server-to-server integration, please review the <a href="./mparticle-import.html">mParticle (import)</a> documentation.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>Once the Branch SDK is integrated into an app, Branch can detect which links lead to installs, re-opens, and users&#39; actions. Enabling this integration and providing your mParticle key/secret will result in Branch automatically forwarding attributed events to mParticle, in the exact format mParticle expects.</p><h3 id="branch-events-sent-to-mparticle" tabindex="-1">Branch events sent to mParticle <a class="header-anchor" href="#branch-events-sent-to-mparticle" aria-label="Permalink to &quot;Branch events sent to mParticle&quot;">​</a></h3><p>Branch will send <strong>attributed installs, opens, commerce events, user lifecycle events, content events, and custom events</strong>. Branch also sends all the data that is attached to the link that drove the attributed events. This will allow you to analyze which campaigns, channels, etc. are helping you acquire and engage users. You can see the list of fields that we send to mParticle <a href="./mparticle-export.html">here</a>.</p><table tabindex="0"><thead><tr><th>Property Name</th><th>Value</th><th>Sourced from</th><th>Example</th></tr></thead><tbody><tr><td><code>event_name</code></td><td>Name of the event</td><td><em>hardcoded</em></td><td>&quot;attribution&quot;</td></tr><tr><td><code>custom_event_type</code></td><td>&quot;attribution&quot;</td><td><em>hardcoded</em></td><td>&quot;attribution&quot;</td></tr><tr><td><code>event_id</code></td><td>Unique ID for the event</td><td>Branch event ID</td><td>469939270182891107</td></tr><tr><td><code>custom_attributes</code></td><td>Branch Link Data Dictionary</td><td>Last Attributed Touch Data for the link to which the event was attributed</td><td>&quot;campaign&quot;: &quot;mParticle test&quot;, &quot;channel&quot;: &quot;Slack&quot;</td></tr><tr><td><code>timestamp_unixtime_ms</code></td><td>timestamp of the event in ms</td><td>event</td><td>1513280479654</td></tr><tr><td><code>device_info</code></td><td>Device Data, like OS Version and country</td><td>Branch User Data for the device</td><td>&quot;os_version&quot;: &quot;10.0&quot;,&quot;device_country&quot;: &quot;US&quot;</td></tr><tr><td><code>user_identities</code></td><td>mParticle customer ID</td><td>mParticle customer ID for the user</td><td>user123abc</td></tr><tr><td><code>application_info</code></td><td>App information like package name</td><td>Branch SDK/App Details</td><td>&quot;application_name&quot;: &quot;Branch-3rdParty-SDK-Testbed&quot;,&quot;application_version&quot;: &quot;1.2.0&quot;</td></tr><tr><td><code>IP</code></td><td>IP of the event</td><td>Device</td><td>192.82.115.928</td></tr></tbody></table><h3 id="mparticle-identity-strategy" tabindex="-1">mParticle Identity Strategy <a class="header-anchor" href="#mparticle-identity-strategy" aria-label="Permalink to &quot;mParticle Identity Strategy&quot;">​</a></h3><p>Branch sends several identifiers to mParticle as part of the webhook payload. Notably, these are:</p><table tabindex="0"><thead><tr><th>Identifier</th><th>Value</th><th>mParticle Field</th><th>Example</th><th>Notes</th></tr></thead><tbody><tr><td>IDFA</td><td>Apple&#39;s ID For Advertising</td><td>ios_advertising_id</td><td>EA7583CD-A667-48BC-B806-42ECB2B48606</td><td>Sent with iOS events unless user has Limit Ad Tracking on</td></tr><tr><td>IDFV</td><td>Apple&#39;s ID For Vendor</td><td>ios_idfv</td><td>74683E89-E010-4A73-B3ED-2741D4E5FFFE</td><td>Sent with most iOS events</td></tr><tr><td>AAID</td><td>Android&#39;s Android Advertising ID</td><td>android_advertising_id</td><td>cdda802e-fb9c-47ad-0794d394c913</td><td>Sent with Android events</td></tr><tr><td>Android ID</td><td>Android ID</td><td>android_uuid</td><td>404fc0aea39abcdf</td><td>Sometimes sent on Android events if AAID isn&#39;t present</td></tr><tr><td>Customer ID</td><td>mParticle Customer ID</td><td>customerid</td><td>user123abc</td><td>Customer Identifier mapped from Branch <code>developer_identity</code></td></tr><tr><td>mPID</td><td>mParticle ID</td><td>mpid</td><td>user123abc</td><td>mParticle ID identifier mapped from Branch <code>developer_identity</code></td></tr></tbody></table><p>Please ensure your mParticle identity strategy lines up with the identifiers sent by Branch. If it doesn&#39;t, mParticle may end up creating new profiles for events sent from Branch rather than attaching these events to the correct existing profiles.</p><p>The Customer ID or mPID is of particular importance. If you set developer_identity with Branch (docs here), Branch will automatically map this to mParticle&#39;s Customer ID or mPID. Make sure the value you set here with Branch corresponds to the value you&#39;re using for that user in mParticle.</p><p>If you&#39;re using a different value in <code>developer_identity</code> please reach out to your Branch account team.</p><h2 id="what-does-it-look-like" tabindex="-1">What does it look like? <a class="header-anchor" href="#what-does-it-look-like" aria-label="Permalink to &quot;What does it look like?&quot;">​</a></h2><p>Branch events will appear as a <strong>Custom Attribution Event</strong> in mParticle. You can then export Branch data to your other data sources.</p><p>Branch events are mapped as follows:</p><ul><li>mParticle Event Type = Custom Event</li><li>mParticle Custom Event Type = attribution</li></ul><p>The mParticle Event Name depends on the type of event:</p><ul><li>Install = attribution</li><li>Open = re-engagement</li><li>All Others = Branch Event Name</li></ul><p>For information on how to test your integration and see more detailed data, please review our <a href="./mparticle.html#section-testing-your-integration">testing instructions below</a>.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable mParticle (export), you need to have completed the following:</p><ol><li><p>Admin access to your <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Have the Advanced Data Feeds add-on enabled on your Branch account. Advanced Data Feeds can be included as an add-on to both the Engagement and Performance <a href="./packaging.html">products</a>.</p></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p></li><li><p>Implement the mParticle SDK</p><ul><li>Implemented the <a href="https://developer.apple.com/documentation/adsupport" target="_blank" rel="noreferrer">AdSupportFramework</a> on iOS and <a href="https://developers.google.com/android/guides/setup" target="_blank" rel="noreferrer">Google Play Services library</a> on Android.</li></ul></li><li><p>Admin access to your mParticle account.</p></li></ol><h2 id="enable-mparticle-export" tabindex="-1">Enable mParticle (export) <a class="header-anchor" href="#enable-mparticle-export" aria-label="Permalink to &quot;Enable mParticle (export)&quot;">​</a></h2><h2 id="_1-retrieve-your-mparticle-key-secret" tabindex="-1">1. Retrieve your mParticle Key &amp; Secret <a class="header-anchor" href="#_1-retrieve-your-mparticle-key-secret" aria-label="Permalink to &quot;1. Retrieve your mParticle Key &amp; Secret&quot;">​</a></h2><p>Find your mParticle key &amp; secret and enter it into the Branch Dashboard.</p><ol><li><p>Navigate to <a href="https://app.mparticle.com" target="_blank" rel="noreferrer">https://app.mparticle.com</a> and log into the Dashboard.</p></li><li><p>In the dashboard, navigate to the <a href="https://app.mparticle.com/directory" target="_blank" rel="noreferrer"><strong>Directory</strong></a> and search for Branch .</p></li><li><p>Click the Branch tile, and click <strong>Add Branch Metrics to Setup</strong></p></li><li><p>Select the <strong>Input Feed</strong> Integration Type and click <strong>Go to Setup</strong></p></li><li><p>Specify the following configuration parameters:</p><ul><li>Configuration Name</li><li>Act as Application <em>(select the right platform here)</em></li></ul></li><li><p>Copy your server to server key and secret - you&#39;ll enter them into the Branch dashboard in a moment.</p></li></ol><h2 id="_2-enable-mparticle-export-in-branch" tabindex="-1">2. Enable mParticle (Export) in Branch <a class="header-anchor" href="#_2-enable-mparticle-export-in-branch" aria-label="Permalink to &quot;2. Enable mParticle (Export) in Branch&quot;">​</a></h2><ol><li>On the Branch Dashboard (dashboard.branch.io), navigate to the <a href="https://dashboard.branch.io/data-feeds/integrations" target="_blank" rel="noreferrer">Integrations page</a>.</li><li>Search for mParticle and click on the tile.</li><li>Enter your mParticle key &amp; secret and hit <strong>Enable</strong>.</li></ol><h2 id="_3-verify-the-integration" tabindex="-1">3. Verify the integration <a class="header-anchor" href="#_3-verify-the-integration" aria-label="Permalink to &quot;3. Verify the integration&quot;">​</a></h2><p>To see the data being passed to mParticle in more detail, you can set up a webhook to Requestbin. This will allow you to send only a subset of your Branch events to Requestbin and verify the data is coming through as expected.</p><ol><li><p>Enable the Branch Data Integration above. Install your app from a Branch link to generate some data in mParticle. It can take up to an hour for the custom attributes to show in mParticle.</p></li><li><p>Create a Branch link from the Short Links section of the dashboard, with a campaign of <em>branch_test</em>.</p></li><li><p>In mParticle, navigate to the Directory in mParticle and add <strong>Webhooks</strong> as an option. Add a Requestbin URL generated from <a href="https://requestbin.com/?" target="_blank" rel="noreferrer">https://requestb.in</a>.</p></li><li><p>To refine the data being sent to the webhook, navigate to <strong>Connections &gt; Connect</strong>.</p></li><li><p>Select the Branch Feed as the input, and <strong>Webhooks</strong> as the output.</p></li><li><p>Finally, view the Requestbin. You can do this by appending <strong>?inspect</strong> to your requestbin URL. You should be able to copy paste the POST body from the request bin into a JSON formatter like <a href="https://jsonlint.com/" target="_blank" rel="noreferrer">https://jsonlint.com/</a> to view the event details.</p></li><li><p>Once you&#39;re done testing, delete the webhook.</p></li></ol><h2 id="support" tabindex="-1">Support <a class="header-anchor" href="#support" aria-label="Permalink to &quot;Support&quot;">​</a></h2><h4 id="why-doesn-t-branch-require-the-mparticle-customer-id" tabindex="-1">Why doesn&#39;t Branch require the mParticle customer ID? <a class="header-anchor" href="#why-doesn-t-branch-require-the-mparticle-customer-id" aria-label="Permalink to &quot;Why doesn&#39;t Branch require the mParticle customer ID?&quot;">​</a></h4><p>Branch doesn&#39;t require the mParticle customer ID because it has usually not been set upon installing the app. The usual workflow for a user is to install the app, then have a confirmed login about thirty seconds later. The Branch install event fires immediately upon install and therefore occurs before the login event, so it does not have the logged-in customer ID before it is sent to mParticle. However, you can join install events for a customer using the device ID attached to the install and login events.</p>',39)])])}const m=e(i,[["render",n]]);export{u as __pageData,m as default};
